1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
9	const FOLLOWUP_DISCOUNT_RATE = 0.15;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	  rune: 250,
26	  moonstone: 250,
27	};
28	
29	const DEDUCTIBLE = 100;
30	const CAP_MULTIPLIER = 2;
31	
32	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
33	type QuoteStep = { op: "quote"; items: Item[] };
34	type Damage = { itemType: string; amount: number };
35	type Incident = { cause: string; damages: Damage[] };
36	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
37	type Step = QuoteStep | ClaimStep;
38	type Customer = { yearsWithMHPCO: number };
39	type Scenario = { customer: Customer; steps: Step[] };
40	
41	const policyInsuranceSum = (items: Item[]): number =>
42	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
43	
44	const claimResult = (policyItems: Item[], step: ClaimStep) => {
45	  const cap = CAP_MULTIPLIER * policyInsuranceSum(policyItems);
46	  const payout = step.incident.damages[0].amount - DEDUCTIBLE;
47	  return { payout, remainingCap: cap - payout };
48	};
49	
50	const sum = (numbers: number[]): number =>
51	  numbers.reduce((total, n) => total + n, 0);
52	
53	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
54	
55	const isBlockOfThreeAlike = (items: Item[]): boolean =>
56	  items.length === 3 && items.every((item) => item.type === items[0].type);
57	
58	const groupByType = (items: Item[]): Item[][] => {
59	  const groups: Record<string, Item[]> = {};
60	  for (const item of items) {
61	    (groups[item.type] ||= []).push(item);
62	  }
63	  return Object.values(groups);
64	};
65	
66	const groupBasePremium = (group: Item[]): number =>
67	  isBlockOfThreeAlike(group)
68	    ? BLOCK_OF_THREE_BASE_PREMIUM
69	    : sum(group.map(itemBasePremium));
70	
71	const itemsBasePremium = (items: Item[]): number =>
72	  sum(groupByType(items).map(groupBasePremium));
73	
74	const rateIfApplies = (amount: number, applies: boolean, rate: number): number =>
75	  applies ? amount * rate : 0;
76	
77	const cursedSurcharge = (item: Item): number =>
78	  rateIfApplies(itemBasePremium(item), item.cursed === true, CURSED_SURCHARGE_RATE);
79	
80	const highEnchantmentSurcharge = (item: Item): number =>
81	  rateIfApplies(
82	    itemBasePremium(item),
83	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
84	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
85	  );
86	
87	const itemSurchargesTotal = (items: Item[]): number =>
88	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
89	
90	const firstInsuranceSurcharge = (basePremium: number): number =>
91	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
92	
93	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
94	  rateIfApplies(
95	    basePremium,
96	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS,
97	    LOYALTY_DISCOUNT_RATE,
98	  );
99	
100	const followupDiscount = (basePremium: number, quoteIndex: number): number =>
101	  rateIfApplies(basePremium, quoteIndex >= 1, FOLLOWUP_DISCOUNT_RATE);
102	
103	const quotePremiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
104	  const policyBase = itemsBasePremium(items);
105	  return Math.ceil(
106	    policyBase +
107	      itemSurchargesTotal(items) +
108	      firstInsuranceSurcharge(policyBase) -
109	      loyaltyDiscount(policyBase, customer) -
110	      followupDiscount(policyBase, quoteIndex) +
111	      PROCESSING_FEE,
112	  );
113	};
114	
115	const quoteStepResult = (step: QuoteStep, customer: Customer, quoteIndex: number) =>
116	  ({ premium: quotePremiumFor(step.items, customer, quoteIndex) });
117	
118	export const runScenario = (input: Scenario): unknown => {
119	  const results: unknown[] = [];
120	  const quotedPolicies: Item[][] = [];
121	  let quoteIndex = 0;
122	  for (const step of input.steps) {
123	    if (step.op === "quote") {
124	      results.push(quoteStepResult(step, input.customer, quoteIndex));
125	      quotedPolicies.push(step.items);
126	      quoteIndex += 1;
127	    } else {
128	      results.push(claimResult(quotedPolicies[step.policy], step));
129	    }
130	  }
131	  return { results };
132	};
